import * as React from "react";
import { cn } from "@/lib/utils";
import { focusRingInset, transitions } from "@/lib/primitives";
import { Collapse } from "@/lib/motion";

export interface RevealProps extends React.HTMLAttributes<HTMLDivElement> {
  /** Label text shown on the toggle button */
  label?: string;
  /** Start in the open state */
  defaultOpen?: boolean;
}

/**
 * Reveal — animated click-to-reveal panel for answers, hints, and spoilers.
 *
 * Unlike the native <details>-based Spoiler, Reveal uses the Collapse
 * primitive so the open/close transition is smooth.
 *
 * @example
 * <Reveal label="Show solution">
 *   The answer is to use a hash map for O(1) lookups.
 * </Reveal>
 */
export const Reveal = React.forwardRef<HTMLDivElement, RevealProps>(
  (
    {
      label = "Show answer",
      defaultOpen = false,
      children,
      className,
      ...props
    },
    ref,
  ) => {
    const [open, setOpen] = React.useState(defaultOpen);

    return (
      <div
        ref={ref}
        className={cn(
          "my-4 overflow-hidden rounded-lg border border-border bg-card",
          className,
        )}
        {...props}
      >
        <button
          type="button"
          onClick={() => setOpen((v) => !v)}
          aria-expanded={open}
          className={cn(
            "flex w-full items-center justify-between px-4 py-3",
            "text-sm font-medium text-foreground",
            transitions.colors,
            "hover:bg-muted/50",
            focusRingInset,
          )}
        >
          <span>{label}</span>
          <svg
            xmlns="http://www.w3.org/2000/svg"
            width="16"
            height="16"
            viewBox="0 0 24 24"
            fill="none"
            stroke="currentColor"
            strokeWidth="2"
            strokeLinecap="round"
            strokeLinejoin="round"
            aria-hidden="true"
            className={cn(
              "shrink-0 text-muted-foreground",
              transitions.transform,
              open && "rotate-180",
            )}
          >
            <path d="m6 9 6 6 6-6" />
          </svg>
        </button>

        <Collapse open={open}>
          <div className="border-t border-border px-4 py-3 text-sm text-muted-foreground">
            {children}
          </div>
        </Collapse>
      </div>
    );
  },
);
Reveal.displayName = "Reveal";

/**
 * Design primitives
 *
 * Shared Tailwind class strings extracted from patterns that repeat across
 * every component. Import these instead of copy-pasting the same strings.
 *
 * Usage:
 *   import { focusRing, surface, transitions } from "@/lib/primitives"
 *   className={cn(surface, focusRing, className)}
 */

/** Full focus-visible ring used on every interactive element */
export const focusRing =
  "focus-visible:outline-none focus-visible:ring-2 focus-visible:ring-ring focus-visible:ring-offset-2 focus-visible:ring-offset-background";

/** Inset focus ring (for buttons inside bordered containers) */
export const focusRingInset =
  "focus-visible:outline-none focus-visible:ring-2 focus-visible:ring-ring focus-visible:ring-inset";

/** Bordered muted surface — code blocks, accordion, inline containers */
export const surface = "rounded-lg border border-border bg-muted";

/** Card surface — white/card background with shadow */
export const cardSurface = "rounded-lg border border-border bg-card shadow-sm";

/** Popover surface — used for tooltips, menus */
export const popoverSurface =
  "rounded-md border border-border bg-popover text-popover-foreground shadow-md";

/** Standard small muted body text */
export const mutedText = "text-sm text-muted-foreground";

/** Block-level vertical rhythm used by all prose components */
export const blockSpacing = "my-6";

/** Consistent transition timings */
export const transitions = {
  colors: "transition-colors duration-200",
  all: "transition-all duration-200",
  transform: "transition-transform duration-200",
  opacity: "transition-opacity duration-200",
} as const;

/** Chevron SVG (reused in accordion, reveal, spoiler) */
export const chevronPath = "m6 9 6 6 6-6";

import * as React from "react";

export interface CollapseProps {
  /** Whether the content is visible */
  open: boolean;
  children: React.ReactNode;
  className?: string;
}

/**
 * Collapse — animated height transition using CSS grid-template-rows.
 *
 * Technique: the outer div transitions between `grid-template-rows: 0fr`
 * (collapsed) and `1fr` (expanded). The inner div clips overflow.
 * This avoids JS height measurement and handles dynamic content naturally.
 *
 * @example
 * <Collapse open={isOpen}>
 *   <div className="py-4">content</div>
 * </Collapse>
 */
export function Collapse({ open, children, className }: CollapseProps) {
  return (
    <div
      aria-hidden={!open}
      style={{
        display: "grid",
        gridTemplateRows: open ? "1fr" : "0fr",
        transition: "grid-template-rows 220ms cubic-bezier(0.4, 0, 0.2, 1)",
      }}
      className={className}
    >
      <div style={{ overflow: "hidden" }}>{children}</div>
    </div>
  );
}
